import asyncio
from openai import AsyncOpenAI

client = AsyncOpenAI()

async def monitor_run_latency(thread_id, run_id, timeout=120):
    start = asyncio.get_event_loop().time()

    while True:
        run = await client.beta.threads.runs.retrieve(
            thread_id=thread_id, run_id=run_id
        )

        elapsed = asyncio.get_event_loop().time() - start
        if elapsed > timeout:
            return {
                'anomaly': True,
                'duration': elapsed,
                'status': run.status,
                'last_error': run.last_error,
                'steps': len(run.required_action.submit_tool_outputs.tool_calls)
            }

        if run.status in ['completed', 'failed', 'cancelled']:
            return {'anomaly': elapsed > 90, 'duration': elapsed}

        await asyncio.sleep(1)

const OpenAI = require('openai');

const openai = new OpenAI();

async function detectToolLoops(threadId, runId) {
  const run = await openai.beta.threads.runs.retrieve(threadId, runId);

  if (run.status !== 'requires_action') return null;

  const toolCalls = run.required_action.submit_tool_outputs.tool_calls;
  const callSignatures = toolCalls.map(tc => 
    `${tc.function.name}:${JSON.stringify(tc.function.arguments).slice(0, 100)}`
  );

  const duplicates = callSignatures.filter((sig, idx) => 
    callSignatures.indexOf(sig) !== idx
  );

  if (duplicates.length > 2) {
    return {
      anomaly: true,
      loopCount: duplicates.length,
      toolName: toolCalls[0].function.name,
      recommendation: 'implement_tool_cache'
    };
  }
  return null;
}

