async function debouncedToolCall(threadId, runId) {
  const run = await openai.beta.threads.runs.retrieve(threadId, runId);

  const toolCalls = run.required_action?.submit_tool_outputs?.tool_calls || [];
  const cacheKey = toolCalls.map(tc => `${tc.function.name}:${tc.function.arguments}`).join('|');

  if (toolCache.has(cacheKey)) {
    const cached = toolCache.get(cacheKey);
    return await openai.beta.threads.runs.submit_tool_outputs(
      threadId, runId, { tool_outputs: cached }
    );
